declare @baseCurrency varchar(32)
select @baseCurrency = rtrim(val) from options where name = 'm_ma_nt0'
if exists(select * from @@table where tk = @tk and ma_nt = @baseCurrency) begin
  select 'this._baseCurrency=''' + @baseCurrency + ''';onChangeCurrency&Identification;(this.getItem(''ma_nt''));active$FormAccount(this);' as message
  return
end else begin
  select 'this._baseCurrency=''' + @baseCurrency + ''';active$FormAccount(this);' as message
  return
end






select 'close$FormAccount(this);' as message
return







select 'onChangeCurrency&Identification;(this.getItem(''ma_nt''));' as message
return







declare @$exists nvarchar(512), @$containConflict nvarchar(512), @$updateConflict nvarchar(512), @$recordHasBeenChanged nvarchar(512), @$deleteConflict nvarchar(512), @$parentAccount$Conflict nvarchar(512), @$whenARAPCheckFail nvarchar(512), @$updateWhenHasChildren nvarchar(512), @$deleteWhenHasChildren nvarchar(512), @$coincidentConflict nvarchar(512), @$childAccount$Conflict nvarchar(512)
select @$exists = case when @@language = 'v' then N'Tài khoản <span class="Highlight">%s</span> đã có trong danh mục tài khoản.' else N'The account <span class="Highlight">%s</span> already exists.' end
select @$containConflict = case when @@language = 'v' then N'Tài khoản <span class="Highlight">%s</span> lồng nhau với một tài khoản khác cùng cấp.' else N'The account <span class="Highlight">%s</span> is nested with an existing one in the same level.' end
select @$updateConflict = case when @@language = 'v' then N'Tài khoản <span class="Highlight">%s</span> đã phát sinh, không thể sửa được.' else N'Cannot edit the account <span class="Highlight">%s</span>. It has already been used.' end
select @$deleteConflict = case when @@language = 'v' then N'Tài khoản <span class="Highlight">%s</span> đã phát sinh, không thể xóa được.' else N'Cannot delete the account <span class="Highlight">%s</span>. It has already been used.' end
select @$recordHasBeenChanged = case when @@language = 'v' then N'Tài khoản <span class="Highlight">%s</span> đã được sửa hoặc xóa bởi người sử dụng khác.' else N'The account <span class="Highlight">%s</span> has been modified or deleted by another user.' end
select @$parentAccount$Conflict = case when @@language = 'v' then N'Tài khoản mẹ <span class="Highlight">$s</span> đã phát sinh, không thể lưu được.' else N'Cannot save the parent account <span class="Highlight">$s</span>. It has already been used.' end
select @$coincidentConflict = case when @@language = 'v' then N'Tài khoản mẹ và con không được trùng nhau.' else N'Invalid parent account. It is coincident with account.' end

select @$whenARAPCheckFail = case when @@language = 'v' then N'Kiểm tra lại khai báo của tài khoản công nợ này.' else N'Check AR/AP information of this account' end
select @$updateWhenHasChildren = case when @@language = 'v' then N'Tài khoản <span class="Highlight">%s</span> đã có các tài khoản con, không sửa được trường tài khoản.' else N'Sub-account of <span class="Highlight">%s</span> has been made, cannot edit the account field.' end
select @$deleteWhenHasChildren = case when @@language = 'v' then N'Tài khoản <span class="Highlight">%s</span> đã có các tài khoản con, không xóa được.' else N'Sub-account of <span class="Highlight">%s</span> has been made, cannot delete this account.' end

select @$childAccount$Conflict = case when @@language = 'v' then N'Các ký tự bắt đầu của tài khoản phải được khai báo trùng so với tài khoản mẹ.' else N'The ordinal number of each sub-account must be added to the right of the number of its parent account.' end






        &CheckChildAccountAndParentAccount;
        &CheckARAPAccount;
        &CheckParentAccount;

if exists(select * from @@table where tk = @tk) begin
  select 'tk' as field, replace(@$exists, '%s', rtrim(@tk)) as message
  return
end

select @loai_tk = case when exists(select * from @@table where tk_me = @tk) then 0 else 1 end
select @bac_tk = case when @tk_me = '' then 1 else isnull((select bac_tk from @@table where tk = @tk_me), 0) + 1 end
if exists(select * from @@table where bac_tk = @bac_tk and ((tk like rtrim(@tk) + '%') or (@tk like rtrim(tk) + '%'))) begin
  select 'tk' as field, replace(@$containConflict, '%s', rtrim(@tk)) as message
  return
end
&UnitBeforeInsert;
select @datetime0 = getdate(), @datetime2 = getdate(), @user_id0 = @@userID, @user_id2 = @@userID

        &UpdateParentAccountType;
        &RevertAccountBalance;





        &UnitPostInsert;





        &CheckChildAccountAndParentAccount;
        &CheckARAPAccount;

if @tk <> $tk.OldValue and exists(select 1 from @@table where tk_me = $tk.OldValue) begin
  select 'tk' as field, replace(@$updateWhenHasChildren, '%s', rtrim($tk.OldValue)) as message
  return
end

if not exists(select 1 from @@table where tk = $tk.OldValue) begin
  select 'tk' as field, replace(@$recordHasBeenChanged, '%s', rtrim($tk.OldValue)) as message
  return
end

if @tk <> $tk.OldValue begin
  if exists(select 1 from @@table where tk = @tk and tk <> $tk.OldValue) begin
    select 'tk' as field, replace(@$exists, '%s', rtrim(@tk)) as message
    return
  end

  declare @message nvarchar(255)
  select @message  = replace(@$updateConflict, '%s', rtrim($tk.OldValue))
  if exists(select 1 from cdtk where tk = $tk.OldValue and &AccountBalanceFields; > 0) begin
    select @message as message
    return
  end
  if exists(select 1 from ct00 where tk = $tk.OldValue) begin
    select @message as message
    return
  end

&CheckDirProcessUpdating;
end

if exists(select 1 from @@table where tk_me <> @tk_me and tk = $tk.OldValue) begin&CheckParentAccount; end

declare @bac_tk int
select @bac_tk = case when @tk_me = '' then 1 else isnull((select bac_tk from @@table where tk = @tk_me), 0) + 1 end
if exists(select 1 from @@table where tk <> $tk.OldValue and bac_tk = @bac_tk and ((tk like rtrim(@tk) + '%') or (@tk like rtrim(tk) + '%'))) begin
  select 'tk' as field, replace(@$containConflict, '%s', rtrim(@tk)) as message
  return
end

if @tk = @tk_me begin
  select 'tk_me', @$coincidentConflict as message
  return
end
if @tk <> $tk.OldValue delete cdtk where tk = $tk.OldValue and &AccountBalanceFields; = 0
if exists(select 1 from @@table where tk_me <> @tk_me and tk = $tk.OldValue) begin&RevertAccountBalance; end

        &UnitBeforeUpdate;






declare @loai_tk int
select @loai_tk = case when exists(select * from @@table where tk_me = @tk) then 0 else 1 end
update @@table set loai_tk = @loai_tk, bac_tk = @bac_tk, datetime2 = getdate(), user_id2 = @@userID where tk = @tk

        &UnitPostUpdate;
        &UpdateParentAccountType;






declare @message nvarchar(255), @parentAccount varchar(32)
if exists(select 1 from @@table where tk_me = @tk) begin
  select replace(@$deleteWhenHasChildren, '%s', rtrim(@tk)) as message
  return
end

select @message  = replace(@$deleteConflict, '%s', rtrim(@tk))
if exists(select 1 from cdtk where tk = @tk and &AccountBalanceFields; > 0) begin
  select @message as message
  return
end
if exists(select 1 from ct00 where tk = @tk) begin
  select @message as message
  return
end
&CheckDirProcessDeleting;
select @parentAccount = tk_me from @@table where tk = @tk
if @parentAccount <> '' begin
  if not exists(select 1 from @@table where tk_me = @parentAccount and tk <> @tk) update @@table set loai_tk = 1 where tk = @parentAccount
end
delete cdtk where tk = @tk and &AccountBalanceFields; = 0

        &UnitPostDelete;





        &UnitCheck;







