function active$FormAccount(f) {f.add_onResponseComplete(on$FormAccount$ResponseComplete);&ActiveForm;}
function close$FormAccount(f) {try {f.remove_onResponseComplete(on$FormAccount$ResponseComplete)} catch (ex) {};&CloseForm;}
function on$FormAccount$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'tk');
      break;
    default:
      break;
  }
}
function onChangeCurrency&Identification;(o) {
  var f = o.parentForm, value;
  if (f._action == 'View') return;
  value = (o.value.toUpperCase() == f._baseCurrency.toUpperCase());
  f.getItem('loai_cl_no').disabled = value;
  f.getItem('loai_cl_co').disabled = value;
}

